import { Router } from "express";
import crypto from "crypto";
import { users, nextId } from "../db.js";
import { generateToken } from "../middleware/auth.js";

const router = Router();

function hashPassword(password: string): string {
  return crypto.createHash("sha256").update(password).digest("hex");
}

// POST /auth/register - create a new user and return a JWT token
router.post("/register", (req, res) => {
  const { username, email, password } = req.body;
  if (!username || !email || !password) {
    res
      .status(400)
      .json({ error: "username, email, and password are required" });
    return;
  }
  if (users.find((u) => u.username === username)) {
    res.status(409).json({ error: "Username already taken" });
    return;
  }
  const newUser = {
    id: nextId(users),
    username,
    email,
    password: hashPassword(password),
  };
  users.push(newUser);
  const token = generateToken({ userId: newUser.id, username: newUser.username });
  res.status(201).json({
    token,
    user: { id: newUser.id, username: newUser.username, email: newUser.email },
  });
});

// POST /auth/login - verify credentials and return a JWT token
router.post("/login", (req, res) => {
  const { username, password } = req.body;
  const user = users.find((u) => u.username === username);
  if (!user || user.password !== hashPassword(password)) {
    res.status(401).json({ error: "Invalid credentials" });
    return;
  }
  const token = generateToken({ userId: user.id, username: user.username });
  res.status(200).json({
    token,
    user: { id: user.id, username: user.username, email: user.email },
  });
});

export { router as authRouter };

