import { Router } from "express";
import { posts, nextId } from "../db.js";
import { Post } from "../types.js";
import { authenticateToken } from "../middleware/auth.js";

const router = Router();

// GET /posts - list all posts (public)
router.get("/", (req, res) => {
  res.json(posts);
});

// GET /posts/:id - get a single post (public)
router.get("/:id", (req, res) => {
  const id = parseInt(req.params.id, 10);
  const post = posts.find((p) => p.id === id);
  if (!post) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  res.json(post);
});

// POST /posts - create a new post (requires auth)
router.post("/", authenticateToken, (req, res) => {
  const { title, content } = req.body;
  if (!title || !content) {
    res.status(400).json({ error: "title and content are required" });
    return;
  }
  const newPost: Post = {
    id: nextId(posts),
    title,
    content,
    userId: req.user!.userId,
    createdAt: new Date().toISOString(),
  };
  posts.push(newPost);
  res.status(201).json(newPost);
});

// PUT /posts/:id - update a post (requires auth, owner only)
router.put("/:id", authenticateToken, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  if (posts[index].userId !== req.user!.userId) {
    res.status(403).json({ error: "Forbidden: you do not own this post" });
    return;
  }
  const { title, content } = req.body;
  if (title) posts[index].title = title;
  if (content) posts[index].content = content;
  res.json(posts[index]);
});

// DELETE /posts/:id - delete a post (requires auth, owner only)
router.delete("/:id", authenticateToken, (req, res) => {
  const id = parseInt(req.params.id, 10);
  const index = posts.findIndex((p) => p.id === id);
  if (index === -1) {
    res.status(404).json({ error: "Post not found" });
    return;
  }
  if (posts[index].userId !== req.user!.userId) {
    res.status(403).json({ error: "Forbidden: you do not own this post" });
    return;
  }
  const deleted = posts.splice(index, 1);
  res.json(deleted[0]);
});

export { router as postsRouter };

